   }
   ```

2. **Completion Script Generation**
   ```rust
   #[test]
   fn test_generate_bash_completions() {
       let script = generate_completions(Shell::Bash);
       assert!(script.contains("complete -F"));
       assert!(script.contains("_rp"));
       assert!(script.contains("rp"));
   }

   #[test]
   fn test_generate_zsh_completions() {
       let script = generate_completions(Shell::Zsh);
       assert!(script.contains("#compdef rp"));
       assert!(script.contains("_rp"));
   }

   #[test]
   fn test_generate_fish_completions() {
       let script = generate_completions(Shell::Fish);
       assert!(script.contains("complete -c rp"));
   }

   #[test]
   fn test_completions_include_all_commands() {
       for shell in [Shell::Bash, Shell::Zsh, Shell::Fish] {
           let script = generate_completions(shell);
           assert!(script.contains("start"), "Missing 'start' command for {:?}", shell);
           assert!(script.contains("stop"), "Missing 'stop' command for {:?}", shell);
           assert!(script.contains("status"), "Missing 'status' command for {:?}", shell);
           assert!(script.contains("check"), "Missing 'check' command for {:?}", shell);
       }
   }
