4. **Installation Logic**
   ```rust
   #[test]
   fn test_creates_parent_directory() {
       let temp = tempdir().unwrap();
       let path = temp.path().join("subdir/completions/rp");

       install_completion(Shell::Bash, &path).unwrap();

       assert!(path.exists());
       assert!(path.parent().unwrap().exists());
